// ============================================================
// Theme + global font injection
// ============================================================
const ThemeCtx = createContext({ theme: 'dark', toggle: () => {} });

function GoogleFonts() {
  // Inject Geist + Inter via <link> on mount, plus global smooth scroll
  useEffect(() => {
    if (document.getElementById('chillout-fonts')) return;
    const link = document.createElement('link');
    link.id = 'chillout-fonts';
    link.rel = 'stylesheet';
    link.href = 'https://fonts.googleapis.com/css2?family=Geist:wght@300;400;500;600;700&family=Inter:wght@300;400;500;600;700&display=swap';
    document.head.appendChild(link);
    const style = document.createElement('style');
    style.id = 'chillout-globals';
    style.textContent = `
      html { scroll-behavior: smooth; }
      @media (prefers-reduced-motion: reduce) { html { scroll-behavior: auto; } }
      ::selection { background: rgba(253, 230, 138, 0.4); }
      body { font-feature-settings: 'ss01', 'cv11'; }
    `;
    document.head.appendChild(style);
  }, []);
  return null;
}

// ============================================================
// Live status (Aberto agora / Fechado)
// Mon-Thu 12-23; Fri-Sun 12-01 (next day)
// ============================================================
function useLiveStatus() {
  const [now, setNow] = useState(() => new Date());
  useEffect(() => {
    const tick = setInterval(() => setNow(new Date()), 60000);
    return () => clearInterval(tick);
  }, []);
  const day = now.getDay(); // 0=Sun
  const hour = now.getHours() + now.getMinutes() / 60;
  // Weekend = Fri(5), Sat(6), Sun(0)
  const isWeekend = day === 5 || day === 6 || day === 0;
  const closesAt = isWeekend ? 25 : 23; // 25 = 1am next day
  const isOpen = (hour >= 12 && hour < (isWeekend ? 24 : 23))
              || (day === 6 && hour < 1) // Sat after midnight (was Fri night)
              || (day === 0 && hour < 1) // Sun after midnight
              || (day === 1 && hour < 1); // Mon after midnight (was Sun)
  const closesText = isWeekend ? '12h' : '23h';
  return { isOpen, closesAt: closesText, day };
}

// ============================================================
// Small UI atoms
// ============================================================
function LangSwitcher({ lang, setLang, theme }) {
  const opts = [['pt','PT'],['es','ES'],['en','EN']];
  return (
    <div className="inline-flex items-center gap-3 text-[11px] tracking-[0.15em] font-medium">
      {opts.map(([k,l], i) => (
        <React.Fragment key={k}>
          {i > 0 && <span className={theme === 'dark' ? 'text-stone-600' : 'text-stone-400'}>·</span>}
          <button
            onClick={() => setLang(k)}
            className={`transition-colors ${
              lang === k
                ? (theme === 'dark' ? 'text-amber-200' : 'text-stone-900')
                : (theme === 'dark' ? 'text-stone-500 hover:text-stone-300' : 'text-stone-400 hover:text-stone-700')
            }`}
          >{l}</button>
        </React.Fragment>
      ))}
    </div>
  );
}

function ThemeToggle() {
  const { theme, toggle } = useContext(ThemeCtx);
  return (
    <button
      onClick={toggle}
      aria-label="Toggle theme"
      className={`relative inline-flex items-center justify-center w-9 h-9 rounded-full border transition-all ${
        theme === 'dark'
          ? 'border-stone-700 hover:border-amber-200/40 text-amber-200/80'
          : 'border-stone-300 hover:border-stone-900 text-stone-700'
      }`}
    >
      {theme === 'dark' ? <Sun size={16} strokeWidth={1.5}/> : <Moon size={16} strokeWidth={1.5}/>}
    </button>
  );
}

function Tag({ kind, label, theme }) {
  const styles = theme === 'dark' ? {
    chef: 'bg-amber-200/10 text-amber-200 border-amber-200/30',
    hot:  'bg-red-500/10 text-red-300 border-red-500/30',
    veg:  'bg-emerald-500/10 text-emerald-300 border-emerald-500/30',
  } : {
    chef: 'bg-amber-100 text-amber-900 border-amber-200',
    hot:  'bg-red-50 text-red-700 border-red-200',
    veg:  'bg-emerald-50 text-emerald-800 border-emerald-200',
  };
  const Icon = kind === 'chef' ? Star : kind === 'hot' ? Flame : null;
  return (
    <span className={`inline-flex items-center gap-1 px-2 py-0.5 rounded-full border text-[10px] font-medium uppercase tracking-wider ${styles[kind]}`}>
      {Icon && <Icon size={10} strokeWidth={2.5}/>}{label}
    </span>
  );
}

function LiveBadge({ t, theme }) {
  const { isOpen, closesAt } = useLiveStatus();
  return (
    <span className={`inline-flex items-center gap-2.5 px-4 py-1.5 rounded-full border text-[11px] tracking-[0.15em] uppercase backdrop-blur-sm ${
      theme === 'dark' ? 'border-stone-700 text-stone-300' : 'border-white/35 text-white/90 bg-black/15'
    }`}>
      <span className="relative flex h-2 w-2">
        <span className={`absolute inline-flex h-full w-full rounded-full ${isOpen ? 'bg-emerald-400' : 'bg-stone-500'} animate-ping opacity-50`}></span>
        <span className={`relative inline-flex rounded-full h-2 w-2 ${isOpen ? 'bg-emerald-400' : 'bg-stone-500'}`}></span>
      </span>
      {isOpen ? <>{t.openNow} · {t.untilLabel} {closesAt}</> : t.closedNow}
    </span>
  );
}

// Title with mixed roman + accent parts (modern restaurant: weight 300 hairline + color accent)
function DisplayTitle({ parts, theme, className = '' }) {
  return (
    <h2 className={`leading-[0.9] tracking-[-0.035em] ${className}`} style={{ fontFamily: "'Geist', 'Inter', system-ui, sans-serif", fontWeight: 300 }}>
      {parts.map((p, i) => (
        i % 2 === 0
          ? <span key={i} className={theme === 'dark' ? 'text-stone-50' : 'text-stone-950'}>{p}</span>
          : <span key={i} className={theme === 'dark' ? 'text-amber-200' : 'text-orange-700'} style={{ fontWeight: 400 }}>{p}</span>
      ))}
    </h2>
  );
}

function DishImage({ id, alt, className }) {
  const src = PHOTOS[id];
  if (!src) {
    return (
      <div className={`flex items-center justify-center bg-gradient-to-br from-stone-800 via-stone-900 to-stone-950 ${className}`}>
        <ChefHat size={28} className="text-amber-200/30" strokeWidth={1.2}/>
      </div>
    );
  }
  return <img src={src} alt={alt} className={className} loading="lazy"/>;
}

function DishCard({ dish, lang, t, theme }) {
  if (dish.special === 'chef-ask' || dish.special === 'bottle-ask') {
    const Icon = dish.special === 'chef-ask' ? ChefHat : Star;
    const isLight = theme === 'light';
    return (
      <article className={`rounded-2xl border overflow-hidden p-5 md:p-6 transition-all ${
        isLight
          ? 'bg-stone-900 text-amber-50 border-stone-800 hover:border-amber-200/30'
          : 'bg-stone-950/50 text-amber-100 border-amber-200/20 hover:border-amber-200/40'
      }`}>
        <div className="flex items-start gap-4">
          <div className={`shrink-0 w-12 h-12 rounded-full flex items-center justify-center ${
            isLight ? 'bg-amber-200/10 border border-amber-200/30 text-amber-200' : 'bg-amber-200/10 border border-amber-200/30 text-amber-200'
          }`}>
            <Icon size={22} strokeWidth={1.5}/>
          </div>
          <div className="flex-1 min-w-0">
            <p className="text-[10px] font-mono text-amber-200/60 tracking-[0.2em] uppercase mb-2">{t.askWaiter}</p>
            <h3 className="text-xl leading-tight mb-1.5" style={{ fontFamily: "'Geist', 'Inter', system-ui, sans-serif" }}>{dish.name}</h3>
            <p className="text-sm text-amber-100/70 leading-relaxed">{dish.d[lang]}</p>
          </div>
        </div>
      </article>
    );
  }

  const cardBg = theme === 'dark'
    ? 'bg-stone-900/40 border-stone-800 hover:border-amber-200/30'
    : 'bg-white border-stone-200 hover:border-orange-300/60 hover:shadow-lg hover:shadow-stone-900/5';
  const titleClr = theme === 'dark' ? 'text-stone-100' : 'text-stone-900';
  const descClr  = theme === 'dark' ? 'text-stone-400' : 'text-stone-600';
  const priceClr = theme === 'dark' ? 'text-amber-200' : 'text-stone-900';
  const idClr    = theme === 'dark' ? 'text-stone-500' : 'text-stone-400';
  const unitsClr = theme === 'dark' ? 'text-stone-500' : 'text-stone-500';

  return (
    <article className={`group relative rounded-2xl border overflow-hidden transition-all duration-300 ${cardBg}`}>
      <div className="flex items-stretch">
        <div className="relative w-28 md:w-32 shrink-0 overflow-hidden">
          <DishImage id={dish.id} alt={dish.name} className="absolute inset-0 w-full h-full object-cover group-hover:scale-105 transition-transform duration-500"/>
        </div>
        <div className="flex-1 min-w-0 p-4 md:p-5 flex items-start justify-between gap-4">
          <div className="flex-1 min-w-0">
            <div className="flex flex-wrap items-center gap-x-2 gap-y-1 mb-1.5">
              <span className={`text-[10px] font-mono tracking-[0.15em] ${idClr}`}>#{dish.id}</span>
              {dish.tags?.map(tg => <Tag key={tg} kind={tg} label={t.tags[tg]} theme={theme}/>)}
            </div>
            <h3 className={`text-lg leading-tight mb-1.5 ${titleClr}`} style={{ fontFamily: "'Geist', 'Inter', system-ui, sans-serif" }}>
              {dish.name}
              {dish.units && <span className={`ml-2 text-xs font-sans font-normal ${unitsClr}`} style={{ fontFamily: "'Geist', 'Inter', sans-serif" }}>· {dish.units} {t.units}</span>}
            </h3>
            <p className={`text-sm leading-relaxed line-clamp-2 ${descClr}`}>{dish.d[lang]}</p>
          </div>
          {dish.price != null && (
            <div className="text-right shrink-0">
              <div className={`text-xl tabular-nums ${priceClr}`} style={{ fontFamily: "'Geist', 'Inter', system-ui, sans-serif" }}>
                <span className={`text-xs mr-0.5 ${idClr}`}>R$</span>{dish.price.toFixed(2).replace('.', ',')}
              </div>
            </div>
          )}
        </div>
      </div>
    </article>
  );
}

// Big editorial featured card: photo top, eyebrow + title below
function FeaturedCard({ dish, lang, t, theme, catLabel }) {
  const isDark = theme === 'dark';
  return (
    <article className={`group cursor-pointer rounded-2xl overflow-hidden border transition-all duration-300 ${
      isDark ? 'border-stone-800 bg-stone-950/30 hover:border-amber-200/30' : 'border-stone-200 bg-white hover:border-orange-300/60 hover:shadow-xl hover:shadow-stone-900/5'
    }`}>
      <div className="relative aspect-square overflow-hidden bg-gradient-to-br from-stone-800 via-stone-900 to-stone-950">
        <DishImage id={dish.id} alt={dish.name} className="absolute inset-0 w-full h-full object-cover group-hover:scale-105 transition-transform duration-700"/>
        <div className="absolute inset-0 bg-gradient-to-t from-stone-950/60 via-transparent to-transparent"/>
        {/* corner ticks (editorial mark) */}
        <div className="absolute top-3 left-3 w-3 h-3 border-l border-t border-amber-200/40"/>
        <div className="absolute top-3 right-3 w-3 h-3 border-r border-t border-amber-200/40"/>
        <div className="absolute bottom-3 left-3 w-3 h-3 border-l border-b border-amber-200/40"/>
        <div className="absolute bottom-3 right-3 w-3 h-3 border-r border-b border-amber-200/40"/>
        <p className="absolute bottom-4 left-4 text-[10px] tracking-[0.25em] uppercase text-amber-100/70">{dish.name} · foto</p>
      </div>
      <div className="p-5 md:p-6">
        <p className={`text-[10px] tracking-[0.25em] uppercase mb-3 ${isDark ? 'text-amber-200' : 'text-orange-700'}`}>{catLabel}</p>
        <h3 className={`text-2xl md:text-[26px] leading-tight mb-2 ${isDark ? 'text-stone-100' : 'text-stone-900'}`} style={{ fontFamily: "'Geist', 'Inter', system-ui, sans-serif" }}>
          {dish.name}
        </h3>
        <p className={`text-sm leading-relaxed mb-4 line-clamp-2 ${isDark ? 'text-stone-400' : 'text-stone-600'}`}>{dish.d[lang]}</p>
        <div className={`flex items-center justify-between pt-4 border-t ${isDark ? 'border-stone-800' : 'border-stone-200'}`}>
          <span className={`text-[10px] font-mono tracking-[0.15em] ${isDark ? 'text-stone-500' : 'text-stone-400'}`}>#{dish.id}</span>
          <span className={`text-base tabular-nums ${isDark ? 'text-amber-200' : 'text-stone-900'}`} style={{ fontFamily: "'Geist', 'Inter', system-ui, sans-serif" }}>
            <span className={`text-xs mr-0.5 ${isDark ? 'text-stone-500' : 'text-stone-400'}`}>R$</span>{dish.price.toFixed(2).replace('.', ',')}
          </span>
        </div>
      </div>
    </article>
  );
}

